	if(b) {

		ll k=extgcd(b,a%b,x,y);

		ll t=x;x=y;

		y=t-a/b*y;

		return k;

	} else {

		x=1;y=0;

		return a;

	}

}

inline ll C(int x) {

	return P*Q[x]%MOD*Q[n-x]%MOD;

}

